import React, { useState } from 'react';
import './quiz.css';

// Import the screen components
import ScreenOne from './Screenone/ScreenOne';
import ScreenTwo from './Screentwo/ScreenTwo';
import ScreenThree from './Screenthree/ScreenThree';
import ScreenFour from './Screenfour/ScreenFour';
import ScreenFive from './Screenfive/ScreenFive';
import ScreenSix from './Screensix/ScreenSix';
import ScreenSeven from './Screenseven/ScreenSeven';

const Quiz = () => {
  const [currentScreen, setCurrentScreen] = useState(1);
  const [userData, setUserData] = useState({
    name: '',
    email: '',
    phone: '',
    gender: ''
  });
  const [healthConditions, setHealthConditions] = useState({
    selectedConditions: [],
    otherConditionDetails: ''
  });
  const [allergies, setAllergies] = useState({
    selectedAllergies: [],
    otherAllergyDetails: ''
  });
  const [dietGoal, setDietGoal] = useState('');
  const [otherDietGoalDetails, setOtherDietGoalDetails] = useState('');
  const [achievementGoals, setAchievementGoals] = useState('');
  const [meetingsPerMonth, setMeetingsPerMonth] = useState('');

  const totalScreens = 7;

  const validateScreen = () => {
    switch (currentScreen) {
      case 2:
        return userData.name && userData.email && userData.phone && userData.gender;
      case 3:
        return healthConditions.selectedConditions.length > 0 || healthConditions.otherConditionDetails;
      case 4:
        return allergies.selectedAllergies.length > 0 || allergies.otherAllergyDetails;
      case 5:
        return dietGoal && (dietGoal !== 'None of the above' || otherDietGoalDetails);
      case 6:
        return achievementGoals && meetingsPerMonth;
      default:
        return true;
    }
  };

  const handleNext = () => {
    if (validateScreen()) {
      setCurrentScreen(prevScreen => Math.min(prevScreen + 1, totalScreens));
    } else {
      alert('Please fill out all required fields.');
    }
  };

  const handleBack = () => {
    setCurrentScreen(prevScreen => Math.max(prevScreen - 1, 1));
  };

  const handleFinish = () => {
    console.log('User Data:', userData);
    console.log('Health Conditions:', healthConditions);
    console.log('Allergies:', allergies);
    console.log('Diet Goal:', dietGoal);
    console.log('Other Diet Goal Details:', otherDietGoalDetails);
    console.log('Achievement Goals:', achievementGoals);
    console.log('Meetings Per Month:', meetingsPerMonth);
    alert('Form submitted successfully!');
    setCurrentScreen(totalScreens);
  };

  const handleUserDataChange = (field, value) => {
    setUserData({
      ...userData,
      [field]: value
    });
  };

  const handleConditionChange = (condition) => {
    setHealthConditions((prevState) => {
      const { selectedConditions } = prevState;
      if (selectedConditions.includes(condition)) {
        return { ...prevState, selectedConditions: selectedConditions.filter(cond => cond !== condition) };
      } else {
        return { ...prevState, selectedConditions: [...selectedConditions, condition] };
      }
    });
  };

  const handleOtherConditionDetailsChange = (value) => {
    setHealthConditions((prevState) => ({
      ...prevState,
      otherConditionDetails: value
    }));
  };

  const handleAllergyChange = (allergy) => {
    setAllergies((prevState) => {
      const { selectedAllergies } = prevState;
      if (selectedAllergies.includes(allergy)) {
        return { ...prevState, selectedAllergies: selectedAllergies.filter(allerg => allerg !== allergy) };
      } else {
        return { ...prevState, selectedAllergies: [...selectedAllergies, allergy] };
      }
    });
  };

  const handleOtherAllergyDetailsChange = (value) => {
    setAllergies((prevState) => ({
      ...prevState,
      otherAllergyDetails: value
    }));
  };

  const handleDietGoalChange = (goal) => {
    setDietGoal(goal);
    if (goal !== 'None of the above') {
      setOtherDietGoalDetails('');
    }
  };

  const handleOtherDietGoalDetailsChange = (value) => {
    setOtherDietGoalDetails(value);
  };

  const handleAchievementGoalsChange = (value) => {
    setAchievementGoals(value);
  };

  const handleMeetingsPerMonthChange = (value) => {
    setMeetingsPerMonth(value);
  };

  const progressPercentage = 10 + ((currentScreen - 1) / (totalScreens - 1)) * 100;

  return (
    <div className="quiz">
      <div className="progress-bar-outer">
        <div className="progress-bar" style={{ width: `${progressPercentage}%` }}>
          <div>{currentScreen} / {totalScreens}</div>
        </div>
      </div>
      <div className="screen-body">
        {currentScreen === 1 && <ScreenOne />}
        {currentScreen === 2 && <ScreenTwo userData={userData} handleUserDataChange={handleUserDataChange} />}
        {currentScreen === 3 && (
          <ScreenThree
            healthConditions={healthConditions}
            handleConditionChange={handleConditionChange}
            handleOtherConditionDetailsChange={handleOtherConditionDetailsChange}
          />
        )}
        {currentScreen === 4 && (
          <ScreenFour
            allergies={allergies}
            handleAllergyChange={handleAllergyChange}
            handleOtherAllergyDetailsChange={handleOtherAllergyDetailsChange}
          />
        )}
        {currentScreen === 5 && (
          <ScreenFive
            dietGoal={dietGoal}
            otherDietGoalDetails={otherDietGoalDetails}
            handleDietGoalChange={handleDietGoalChange}
            handleOtherDietGoalDetailsChange={handleOtherDietGoalDetailsChange}
          />
        )}
        {currentScreen === 6 && (
          <ScreenSix
            achievementGoals={achievementGoals}
            meetingsPerMonth={meetingsPerMonth}
            handleAchievementGoalsChange={handleAchievementGoalsChange}
            handleMeetingsPerMonthChange={handleMeetingsPerMonthChange}
          />
        )}
        {currentScreen === 7 && <ScreenSeven />}
      </div>
      <div className="buttons">
        {currentScreen === 1 && <button onClick={handleNext}>Start</button>}
        {currentScreen > 1 && currentScreen < 6 && (
          <>
            <button onClick={handleBack}>Back</button>
            <button onClick={handleNext}>Next</button>
          </>
        )}
        {currentScreen === 6 && (
          <>
            <button onClick={handleBack}>Back</button>
            <button onClick={handleFinish}>Finish</button>
          </>
        )}
      </div>
    </div>
  );
};

export default Quiz;
